@org.springframework.transaction.annotation.Transactional(readOnly = true)
public java.util.List<UserOrderDto> listActiveUsers() {
    java.util.List<User> users = userRepository.findByStatus("ACTIVE");
    return users.stream()
        .map(u -> new UserOrderDto(u.getId(), u.getEmail(), u.getOrders().size()))
        .toList();
}

